from dataclasses import dataclass, field
from typing import Dict, List
from datetime import datetime

@dataclass
class GuardrailConfig:
    max_harm_rate: float = 0.005        # 0.5% ceiling
    max_refusal_rate_delta: float = 0.02  # treatment refusal rate ≤ control + 2%
    max_subgroup_disparity: float = 0.05  # 5% max gap vs largest subgroup
    evaluation_window_minutes: int = 60

@dataclass
class StakeholderApproval:
    stakeholder_id: str
    role: str         # "product", "legal", "ethics_reviewer"
    approved: bool
    timestamp: datetime
    comment: str = ""

@dataclass
class LaunchGate:
    experiment_id: str
    guardrail_config: GuardrailConfig
    rollback_command: str      # e.g. "flipt disable exp_42"
    rollback_tested_at: datetime
    approvals: List[StakeholderApproval] = field(default_factory=list)

    def is_cleared(self) -> bool:
        required_roles = {"product", "legal", "ethics_reviewer"}
        approved_roles = {a.role for a in self.approvals if a.approved}
        return required_roles.issubset(approved_roles)

    def record_approval(self, stakeholder_id: str, role: str, comment: str = ""):
        self.approvals.append(StakeholderApproval(
            stakeholder_id=stakeholder_id,
            role=role,
            approved=True,
            timestamp=datetime.utcnow(),
            comment=comment
        ))

from dataclasses import dataclass

@dataclass
class ExperimentAnalysisLock:
    """Prevents accessing primary metrics before sample size is reached."""
    experiment_id: str
    required_sample_size_per_arm: int
    primary_metric_locked: bool = True

    def get_primary_metrics(
        self,
        treatment_n: int,
        requester_role: str,
    ) -> dict:
        if self.primary_metric_locked:
            if treatment_n < self.required_sample_size_per_arm:
                raise PermissionError(
                    f"Primary metrics locked: {treatment_n}/{self.required_sample_size_per_arm} "
                    f"samples collected. Only guardrail metrics are available before this threshold."
                )
        # Only ethics reviewers and the experiment platform unlock early for a safety review
        if requester_role not in ("ethics_reviewer", "experiment_platform"):
            raise PermissionError("Primary metrics require experiment owner or ethics reviewer role.")
        return {}  # fetch from metrics store
